+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [getCwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; values: Record<string, unknown> }> = [];
+
+  for (const directory of paths) {
+    for (const format of formats) {
+      const path = await resolvePath(directory, fileName(options.name, format));
+      const content = await readFileIfExists(path);
+      if (typeof content === "undefined") continue;
+      matches.push({ path, values: parseConfig(content, path, format, options.parser) });
+      break;
+    }
+    if (matches.length && !options.mergeConfigs) break;
+  }
+
+  // Earlier search paths win, while values within a file retain their normal order.
+  return {
+    path: matches[0]?.path,
+    values: Object.assign({}, ...matches.reverse().map(({ values }) => values)),
+  };
+}
+
+function fileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : format === ".rc" ? parseRc(content) : JSON.parse(content);
+    if (!isPlainObject(value)) throw new Error("Configuration must be a plain object.");
+    return flatten(value);
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator === -1) throw new Error(`Invalid RC line: ${line}`);
+    const key = trimmed.slice(0, separator).trim();
+    let value = trimmed.slice(separator + 1).trim();
+    if (!key) throw new Error(`Invalid RC line: ${line}`);
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) value = value.slice(1, -1);
+    result[key] = coerceRcValue(value);
+  }
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (/^-?(?:\\d+|\\d*\\.\\d+)$/.test(value)) return Number(value);
+  return value;
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (isPlainObject(child)) Object.assign(result, flatten(child, name));
+    else result[name] = child;
+  }
+  return result;
+}
+
+function camelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, character) => character.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && !Array.isArray(value) &&
+    (Object.getPrototypeOf(value) === Object.prototype || Object.getPrototypeOf(value) === null);
+}
+
+function getCwd(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  return Deno ? Deno.cwd() : process.cwd();
+}
