+async function resolvePath(directory: string, name: string): Promise<string> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  if (Deno) return await Deno.realPath(directory).then((path: string) => `${path}/${name}`).catch(() => `${directory}/${name}`);
+  const { resolve } = await import("node:path");
+  return resolve(directory, name);
